import{c as t,Q as n,j as a,m as o}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Confucius Code Agent: Scalable Agent Scaffolding for Real-World Codebases","description":"","frontmatter":{"title":"Confucius Code Agent: Scalable Agent Scaffolding for Real-World Codebases","authors":"Sherman Wong, Zhenting Qi, Zhaodong Wang, Nathan Hu, Samuel Lin, Jun Ge, Erwin Gao, Wenlin Chen, Yilun Du, Minlan Yu, Ying Zhang","published":"2025-12-11T00:00:00.000Z","source":"https://arxiv.org/abs/2512.10398"},"headers":[],"relativePath":"research/papers/2025-12-11-confucius-code-agent-scalable.md","filePath":"research/papers/2025-12-11-confucius-code-agent-scalable.md","lastUpdated":1779901665000}'),i={name:"research/papers/2025-12-11-confucius-code-agent-scalable.md"};function s(r,e,l,d,c,h){return n(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="confucius-code-agent-scalable-agent-scaffolding-for-real-world-codebases" tabindex="-1">Confucius Code Agent: Scalable Agent Scaffolding for Real-World Codebases <a class="header-anchor" href="#confucius-code-agent-scalable-agent-scaffolding-for-real-world-codebases" aria-label="Permalink to &quot;Confucius Code Agent: Scalable Agent Scaffolding for Real-World Codebases&quot;">​</a></h1><p><strong>Authors</strong>: Sherman Wong, Zhenting Qi, Zhaodong Wang, Nathan Hu, Samuel Lin, Jun Ge, Erwin Gao, Wenlin Chen, Yilun Du, Minlan Yu, Ying Zhang<br><strong>Affiliations</strong>: Meta, Harvard University<br><strong>Published</strong>: December 11, 2025 (v1); updated February 3, 2026 (v6)<br><strong>Source</strong>: <a href="https://arxiv.org/abs/2512.10398" target="_blank" rel="noreferrer">https://arxiv.org/abs/2512.10398</a><br><strong>arXiv ID</strong>: 2512.10398<br><strong>Categories</strong>: cs.CL, cs.AI, cs.LG, cs.SE<br><strong>License</strong>: Creative Commons Attribution 4.0</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>We present the Confucius Code Agent (CCA), an open-source AI software engineering framework designed to operate at industrial scale on real-world codebases. CCA is built on the Confucius SDK, which explicitly balances three complementary axes of design: Agent Experience (AX), User Experience (UX), and Developer Experience (DX). The system provides sophisticated context handling for prolonged reasoning sessions, a persistent note-taking mechanism enabling cross-session learning, and a modular tooling architecture that supports reliable multi-step operations. A meta-agent automates the development and refinement cycle for agent configurations. We demonstrate that <strong>agent scaffold—not only backbone model capability—is a decisive factor in real-world software engineering tasks</strong>. On SWE-Bench-Pro (731 tasks), CCA with Claude 4.5 Opus achieves a Resolve@1 of 54.3%, establishing a new state-of-the-art among published and commercial systems using comparable compute. We additionally introduce PyTorch-Bench, a curated benchmark of eight reproducible GitHub issues enabling qualitative comparison with existing tools. Ablation studies confirm that context management contributes 6.6 percentage points and persistent long-term memory contributes 1.4 percentage points to overall performance.</p><hr><h2 id="_1-introduction" tabindex="-1">1. Introduction <a class="header-anchor" href="#_1-introduction" aria-label="Permalink to &quot;1. Introduction&quot;">​</a></h2><p>Large language models have demonstrated remarkable ability on isolated programming tasks, yet bridging the gap between benchmark performance and real-world software engineering remains an open challenge. Industrial codebases impose constraints that standard benchmarks do not capture: repositories span millions of lines across hundreds of modules, sessions extend over hours rather than minutes, and correct solutions often require iterating across multiple files while maintaining coherent context throughout.</p><p>Prior agent frameworks address subsets of these challenges in isolation. ReAct-style agents extend LLMs with tool use but lack persistent memory. RAG-based approaches retrieve relevant code context but do not adapt based on execution feedback. Specialized agents (e.g., CodeAct, SWE-agent) demonstrate strong benchmark scores yet depend on a single large context window that becomes saturated in prolonged sessions.</p><p>This paper introduces the <strong>Confucius Code Agent (CCA)</strong> and its underlying <strong>Confucius SDK</strong>, which address these limitations through a principled three-axis framework:</p><ul><li><strong>Agent Experience (AX)</strong>: the internal cognitive workspace available to the agent, including hierarchical working memory and compression mechanisms that prevent context overflow while retaining semantically important history.</li><li><strong>User Experience (UX)</strong>: transparency and interpretability through human-readable execution traces and logs, allowing developers to audit and trust agent behavior.</li><li><strong>Developer Experience (DX)</strong>: observability channels, evaluation pipelines, and modular interfaces that enable researchers to extend and experiment with the system.</li></ul><p>The key thesis of this work is that <strong>scaffold design, not backbone model selection alone, is decisive</strong> in real-world software engineering tasks. We support this claim through controlled ablations: holding the backbone model fixed while varying scaffold components produces larger performance deltas than switching between comparable backbone models.</p><h3 id="_1-1-swe-bench-pro" tabindex="-1">1.1 SWE-Bench-Pro <a class="header-anchor" href="#_1-1-swe-bench-pro" aria-label="Permalink to &quot;1.1 SWE-Bench-Pro&quot;">​</a></h3><p>SWE-Bench-Pro is a curated subset of 731 GitHub issues from large open-source repositories. Unlike SWE-Bench Verified, it emphasizes multi-file changes, dependency management, and issues that require understanding of cross-module interactions. CCA achieves the following resolve rates on SWE-Bench-Pro:</p><table tabindex="0"><thead><tr><th>Backbone Model</th><th>Resolve@1</th></tr></thead><tbody><tr><td>Claude 4 Sonnet</td><td>45.5%</td></tr><tr><td>Claude 4.5 Sonnet</td><td>52.7%</td></tr><tr><td>Claude 4.5 Opus</td><td>54.3%</td></tr></tbody></table><p>The 54.3% result with Claude 4.5 Opus establishes a new state-of-the-art on SWE-Bench-Pro, surpassing prior research baselines and commercial alternatives using equivalent hardware resources.</p><h3 id="_1-2-contributions" tabindex="-1">1.2 Contributions <a class="header-anchor" href="#_1-2-contributions" aria-label="Permalink to &quot;1.2 Contributions&quot;">​</a></h3><p>The primary contributions of this work are:</p><ol><li><strong>Confucius SDK</strong>: a fully open-source, modular framework for building software engineering agents, incorporating four core features (F1–F4) described in Section 3.</li><li><strong>Confucius Code Agent</strong>: a production-grade agent built on the SDK, achieving state-of-the-art on SWE-Bench-Pro.</li><li><strong>PyTorch-Bench</strong>: a new qualitative benchmark of eight reproducible PyTorch GitHub issues enabling head-to-head comparison between CCA and Claude Code.</li><li><strong>Empirical analysis</strong> of scaffold components via ablation, quantifying the individual contribution of context management, note-taking, and learned tool-use patterns.</li><li><strong>RL integration pathway</strong>: a trajectory export format designed to support future policy gradient updates, treating agentic execution as a Markov Decision Process.</li></ol><hr><h2 id="_2-related-work" tabindex="-1">2. Related Work <a class="header-anchor" href="#_2-related-work" aria-label="Permalink to &quot;2. Related Work&quot;">​</a></h2><h3 id="_2-1-software-engineering-agents" tabindex="-1">2.1 Software Engineering Agents <a class="header-anchor" href="#_2-1-software-engineering-agents" aria-label="Permalink to &quot;2.1 Software Engineering Agents&quot;">​</a></h3><p>SWE-agent introduced the ACE (Agent-Computer Environment) framework, providing structured tool interfaces for file navigation, code editing, and shell execution. Subsequent systems such as CodeAct, Agentless, and OpenHands expanded tool repertoires and improved planning. However, these systems assume a single extended context window and do not address cross-session knowledge accumulation.</p><h3 id="_2-2-context-management-in-long-horizon-tasks" tabindex="-1">2.2 Context Management in Long-Horizon Tasks <a class="header-anchor" href="#_2-2-context-management-in-long-horizon-tasks" aria-label="Permalink to &quot;2.2 Context Management in Long-Horizon Tasks&quot;">​</a></h3><p>Context window saturation is a known failure mode for agentic systems on long tasks. Prior work addresses this through truncation (discarding old messages), summarization (replacing a window with a condensed representation), and retrieval augmentation (selectively injecting relevant content). CCA&#39;s Architect component extends these approaches by performing semantics-aware adaptive compression that preserves recent messages and high-importance historical steps while discarding low-value intermediate output.</p><h3 id="_2-3-memory-and-continual-learning" tabindex="-1">2.3 Memory and Continual Learning <a class="header-anchor" href="#_2-3-memory-and-continual-learning" aria-label="Permalink to &quot;2.3 Memory and Continual Learning&quot;">​</a></h3><p>Episodic memory in AI agents has been studied in the context of lifelong learning, where agents accumulate knowledge across tasks. MemGPT demonstrated cross-session memory via explicit page management. CCA&#39;s note-taking feature takes a different approach: a dedicated summarization agent distills trajectory information into structured Markdown notes that persist on disk, avoiding the complexity of a separate memory management system.</p><h3 id="_2-4-meta-agents-and-automated-agent-design" tabindex="-1">2.4 Meta-Agents and Automated Agent Design <a class="header-anchor" href="#_2-4-meta-agents-and-automated-agent-design" aria-label="Permalink to &quot;2.4 Meta-Agents and Automated Agent Design&quot;">​</a></h3><p>The meta-agent concept—using one agent to design or improve another—has appeared in AutoGen Meta-Agent, ADAS (Automated Design of Agentic Systems), and AFlow. CCA&#39;s Meta-Agent specifically targets the build-test-improve loop for agent configuration synthesis, guided by natural language specifications and automated evaluation signals.</p><hr><h2 id="_3-the-confucius-sdk" tabindex="-1">3. The Confucius SDK <a class="header-anchor" href="#_3-the-confucius-sdk" aria-label="Permalink to &quot;3. The Confucius SDK&quot;">​</a></h2><p>The Confucius SDK provides the infrastructure on which CCA is built. It is organized around four core features (F1–F4) and a central orchestrator component.</p><h3 id="_3-1-the-confucius-orchestrator" tabindex="-1">3.1 The Confucius Orchestrator <a class="header-anchor" href="#_3-1-the-confucius-orchestrator" aria-label="Permalink to &quot;3.1 The Confucius Orchestrator&quot;">​</a></h3><p>The orchestrator implements a minimal execution loop that drives multi-step agent reasoning. At each step, the orchestrator:</p><ol><li>Constructs the current message context from the hierarchical memory (AX layer).</li><li>Invokes the backbone LLM with the current context and tool bindings.</li><li>Parses the model&#39;s output to identify tool calls or termination signals.</li><li>Dispatches tool calls to registered extensions (F3) and collects results.</li><li>Updates the hierarchical memory and execution trace (UX layer).</li><li>Checks termination conditions (agent-driven stop or iteration limit).</li></ol><p>This loop supports two termination mechanisms: <strong>agent-driven termination</strong>, where the model emits a special token indicating task completion, and <strong>extension-managed continuation</strong>, where an extension component can signal that additional steps are required based on validation logic (e.g., tests still failing).</p><p>The separation between the agent-facing context (AX) and the human-facing trace (UX) is a core design principle: the model sees a compressed, semantically coherent view of history, while logs record the uncompressed execution for auditability.</p><h3 id="_3-2-f1-context-management" tabindex="-1">3.2 F1: Context Management <a class="header-anchor" href="#_3-2-f1-context-management" aria-label="Permalink to &quot;3.2 F1: Context Management&quot;">​</a></h3><p>Software engineering sessions on large codebases can easily exhaust even 200k-token context windows. CCA addresses this with a hierarchical working memory system managed by a dedicated <strong>Architect</strong> agent.</p><p>The Architect operates asynchronously alongside the primary coding agent. When the current context approaches a configurable threshold (default: 80% of the model&#39;s context limit), the Architect:</p><ol><li>Receives the full current message history.</li><li>Produces a structured summary that preserves: the original task specification, key decisions made, relevant file paths and code snippets referenced, and the most recent N messages in full (default: N=10).</li><li>Replaces the compressed portion of the history with this summary.</li></ol><p>This adaptive compression strategy differs from simple truncation in that it explicitly retains semantic importance. Ablation experiments (Section 5.2) show that disabling context management reduces Resolve@1 by 6.6 percentage points on a 100-task subset of SWE-Bench-Pro.</p><p><strong>Implementation detail</strong>: The Architect is itself an LLM call (using a smaller, faster model to reduce latency and cost), and its summaries are formatted in a structured template that includes explicit markers for &quot;decisions made,&quot; &quot;files modified,&quot; and &quot;pending steps.&quot; This structure ensures the primary agent can quickly locate relevant prior context.</p><h3 id="_3-3-f2-note-taking" tabindex="-1">3.3 F2: Note-Taking <a class="header-anchor" href="#_3-3-f2-note-taking" aria-label="Permalink to &quot;3.3 F2: Note-Taking&quot;">​</a></h3><p>While context management addresses within-session memory, cross-session learning requires a different mechanism. CCA implements persistent note-taking via a dedicated <strong>Note-Taking Agent</strong> that operates at session boundaries.</p><p>The Note-Taking Agent performs two types of note generation:</p><p><strong>Proactive notes</strong>: After each successful task resolution, the Note-Taking Agent analyzes the execution trajectory and produces structured Markdown notes covering:</p><ul><li>The category of the resolved issue (e.g., &quot;numpy dtype mismatch,&quot; &quot;missing import in <strong>init</strong>.py&quot;)</li><li>The solution pattern applied</li><li>Files and functions that were modified</li><li>Any non-obvious codebase conventions discovered during resolution</li></ul><p><strong>Hindsight notes</strong>: After a failed attempt (or as a post-hoc audit), the Note-Taking Agent produces notes documenting:</p><ul><li>The diagnostic steps that were attempted</li><li>Why each approach failed</li><li>What information would have led to a correct resolution</li></ul><p>These notes are stored as structured Markdown files on disk and are retrieved at the start of subsequent sessions via semantic search over note embeddings. Cross-session experiments (Section 5.3) demonstrate that persistent notes reduce token consumption by approximately 11k tokens per task and reduce average iteration turns by 3, while improving Resolve@1 by 1.4 percentage points.</p><h3 id="_3-4-f3-extensions" tabindex="-1">3.4 F3: Extensions <a class="header-anchor" href="#_3-4-f3-extensions" aria-label="Permalink to &quot;3.4 F3: Extensions&quot;">​</a></h3><p>The Extensions system provides a modular plugin architecture for attaching tool components to the orchestrator. Each extension is a Python class implementing a typed callback interface with three methods:</p><ul><li><code>on_tool_call(tool_name, arguments)</code>: pre-processing before tool execution (e.g., argument validation, prompt injection)</li><li><code>on_tool_result(tool_name, result)</code>: post-processing of tool output (e.g., result summarization, error classification)</li><li><code>on_iteration_end(context)</code>: end-of-step processing (e.g., checking test suite status, updating state)</li></ul><p>Extensions maintain independent state and communicate with the orchestrator through a typed message-passing interface. This design allows extensions to be developed and tested independently, then composed without modification to the core orchestrator.</p><p><strong>Built-in extensions</strong> in CCA include:</p><ul><li><strong>BashExtension</strong>: wraps shell command execution with timeout management and output truncation</li><li><strong>FileEditExtension</strong>: provides structured file editing with syntax validation</li><li><strong>TestRunnerExtension</strong>: executes test suites and parses pass/fail outcomes</li><li><strong>ContextGuardExtension</strong>: monitors context usage and triggers the Architect when thresholds are exceeded</li></ul><h3 id="_3-5-f4-meta-agent" tabindex="-1">3.5 F4: Meta-Agent <a class="header-anchor" href="#_3-5-f4-meta-agent" aria-label="Permalink to &quot;3.5 F4: Meta-Agent&quot;">​</a></h3><p>The Meta-Agent automates the process of constructing and refining agent configurations. Given a natural language specification of a desired agent capability, the Meta-Agent executes a build-test-improve loop:</p><ol><li><strong>Build</strong>: Generate an initial agent configuration (system prompt, tool bindings, extension setup) from the specification.</li><li><strong>Test</strong>: Evaluate the configuration on a small validation set, collecting success/failure signals.</li><li><strong>Improve</strong>: Analyze failures and revise the configuration, repeating until a success threshold is met or a budget is exhausted.</li></ol><p>The Meta-Agent is used internally to synthesize the prompts and configurations of CCA&#39;s sub-agents, and is exposed as a user-facing tool for customizing agents to domain-specific tasks.</p><hr><h2 id="_4-the-confucius-code-agent" tabindex="-1">4. The Confucius Code Agent <a class="header-anchor" href="#_4-the-confucius-code-agent" aria-label="Permalink to &quot;4. The Confucius Code Agent&quot;">​</a></h2><p>CCA instantiates the Confucius SDK with a specific configuration targeting software engineering on real-world GitHub repositories. The core agent pipeline consists of:</p><ol><li><strong>Retrieval Phase</strong>: Given a GitHub issue, retrieve relevant files using a combination of keyword search, BM25 over the repository index, and embedding-based semantic search.</li><li><strong>Localization Phase</strong>: Narrow the candidate file set by reading file summaries and identifying the specific functions/classes likely to require modification.</li><li><strong>Planning Phase</strong>: The primary coding agent generates a structured plan listing the intended changes, the rationale for each, and the test cases that should pass after the fix.</li><li><strong>Implementation Phase</strong>: The agent executes the plan, making file edits through the FileEditExtension and validating each change with the TestRunnerExtension.</li><li><strong>Verification Phase</strong>: After all edits, a full test suite run confirms the fix does not introduce regressions. If tests fail, the agent enters a debugging sub-loop.</li></ol><h3 id="_4-1-problem-solving-philosophy" tabindex="-1">4.1 Problem-Solving Philosophy <a class="header-anchor" href="#_4-1-problem-solving-philosophy" aria-label="Permalink to &quot;4.1 Problem-Solving Philosophy&quot;">​</a></h3><p>Qualitative analysis on PyTorch-Bench reveals a consistent CCA problem-solving philosophy: <strong>minimal intervention</strong>. When multiple valid solutions exist, CCA prefers the change that modifies the fewest lines and leaves the surrounding code structure intact. This contrasts with Claude Code&#39;s observed tendency toward holistic refactoring, which resolves the immediate issue but may introduce broader structural changes.</p><p>The minimal-intervention philosophy is encoded in the system prompt and is reinforced by the Note-Taking Agent&#39;s annotations of successful resolutions, which explicitly highlight cases where a one-line fix was preferred over a larger restructuring.</p><hr><h2 id="_5-experiments" tabindex="-1">5. Experiments <a class="header-anchor" href="#_5-experiments" aria-label="Permalink to &quot;5. Experiments&quot;">​</a></h2><h3 id="_5-1-swe-bench-pro-main-results" tabindex="-1">5.1 SWE-Bench-Pro Main Results <a class="header-anchor" href="#_5-1-swe-bench-pro-main-results" aria-label="Permalink to &quot;5.1 SWE-Bench-Pro Main Results&quot;">​</a></h3><p>SWE-Bench-Pro consists of 731 GitHub issues from 12 open-source repositories including Django, sympy, and scikit-learn. Issues were selected to require multi-file changes and to be reproducible via provided test harnesses.</p><table tabindex="0"><thead><tr><th>System</th><th>Backbone</th><th>Resolve@1</th></tr></thead><tbody><tr><td>SWE-agent v0.6</td><td>GPT-4o</td><td>29.3%</td></tr><tr><td>Agentless v1.5</td><td>GPT-4o</td><td>33.1%</td></tr><tr><td>OpenHands CodeAct</td><td>Claude 3.5 Sonnet</td><td>41.0%</td></tr><tr><td>Claude Code (commercial)</td><td>Claude 4.5</td><td>51.2%</td></tr><tr><td><strong>CCA (ours)</strong></td><td>Claude 4 Sonnet</td><td><strong>45.5%</strong></td></tr><tr><td><strong>CCA (ours)</strong></td><td>Claude 4.5 Sonnet</td><td><strong>52.7%</strong></td></tr><tr><td><strong>CCA (ours)</strong></td><td>Claude 4.5 Opus</td><td><strong>54.3%</strong></td></tr></tbody></table><p>CCA with Claude 4.5 Opus achieves 54.3%, surpassing all reported baselines including the commercial Claude Code system.</p><h3 id="_5-2-ablation-study-context-management" tabindex="-1">5.2 Ablation Study: Context Management <a class="header-anchor" href="#_5-2-ablation-study-context-management" aria-label="Permalink to &quot;5.2 Ablation Study: Context Management&quot;">​</a></h3><p>To isolate the contribution of F1 (Context Management), we ran CCA on a 100-task subset of SWE-Bench-Pro with context management disabled (replacing adaptive compression with simple truncation of messages beyond the context limit).</p><table tabindex="0"><thead><tr><th>Configuration</th><th>Resolve@1 (100-task subset)</th></tr></thead><tbody><tr><td>CCA full (with Architect)</td><td>52.0%</td></tr><tr><td>CCA without context management</td><td>45.4%</td></tr><tr><td>Delta</td><td><strong>+6.6 pp</strong></td></tr></tbody></table><p>The 6.6 percentage point improvement demonstrates that the Architect&#39;s semantics-aware compression provides substantially more useful context than naive truncation, particularly on tasks requiring reference to early-session discoveries.</p><h3 id="_5-3-ablation-study-long-term-memory" tabindex="-1">5.3 Ablation Study: Long-Term Memory <a class="header-anchor" href="#_5-3-ablation-study-long-term-memory" aria-label="Permalink to &quot;5.3 Ablation Study: Long-Term Memory&quot;">​</a></h3><p>Cross-session experiments using a subset of 50 PyTorch issues tested whether persistent notes from prior sessions improve resolution of related subsequent issues.</p><table tabindex="0"><thead><tr><th>Configuration</th><th>Resolve@1</th><th>Avg. Tokens/Task</th><th>Avg. Turns/Task</th></tr></thead><tbody><tr><td>CCA with persistent notes</td><td>56.0%</td><td>87,400</td><td>14.2</td></tr><tr><td>CCA without persistent notes</td><td>54.6%</td><td>98,400</td><td>17.2</td></tr><tr><td>Delta</td><td><strong>+1.4 pp</strong></td><td><strong>−11,000 tokens</strong></td><td><strong>−3.0 turns</strong></td></tr></tbody></table><p>Persistent notes improve resolve rate while simultaneously reducing computational cost, as the agent avoids re-discovering codebase conventions and repeating failed diagnostic approaches.</p><h3 id="_5-4-pytorch-bench-qualitative-comparison" tabindex="-1">5.4 PyTorch-Bench Qualitative Comparison <a class="header-anchor" href="#_5-4-pytorch-bench-qualitative-comparison" aria-label="Permalink to &quot;5.4 PyTorch-Bench Qualitative Comparison&quot;">​</a></h3><p>PyTorch-Bench consists of eight GitHub issues from the PyTorch repository selected for their reproducibility, self-contained nature, and range of difficulty (2 easy, 4 medium, 2 hard by the authors&#39; classification). Both CCA and Claude Code were run on each issue; solutions were evaluated by the research team for correctness and code quality.</p><p>Key qualitative findings:</p><ul><li>CCA resolved 6/8 issues; Claude Code resolved 6/8 issues (different overlapping sets)</li><li>CCA produced smaller diffs (median 23 lines changed vs. 47 for Claude Code)</li><li>Claude Code produced more comprehensive test additions alongside fixes</li><li>CCA more frequently identified the root cause in fewer diagnostic steps</li></ul><p>The complementary strengths suggest that ensemble or collaborative approaches between the two systems could exceed either in isolation.</p><hr><h2 id="_6-discussion" tabindex="-1">6. Discussion <a class="header-anchor" href="#_6-discussion" aria-label="Permalink to &quot;6. Discussion&quot;">​</a></h2><h3 id="_6-1-scaffold-as-a-first-class-research-variable" tabindex="-1">6.1 Scaffold as a First-Class Research Variable <a class="header-anchor" href="#_6-1-scaffold-as-a-first-class-research-variable" aria-label="Permalink to &quot;6.1 Scaffold as a First-Class Research Variable&quot;">​</a></h3><p>A recurring finding across our experiments is that scaffold design choices—context compression strategy, note structure, extension composition—produce performance deltas comparable to or exceeding those from backbone model upgrades. This suggests that the research community should treat scaffold design as a first-class variable in software engineering agent research, comparable in importance to model selection.</p><h3 id="_6-2-towards-reinforcement-learning-integration" tabindex="-1">6.2 Towards Reinforcement Learning Integration <a class="header-anchor" href="#_6-2-towards-reinforcement-learning-integration" aria-label="Permalink to &quot;6.2 Towards Reinforcement Learning Integration&quot;">​</a></h3><p>CCA&#39;s trajectory export format is designed with RL integration in mind. Each execution trajectory is serialized as a sequence of (state, action, reward, next_state) tuples compatible with standard policy gradient frameworks. The reward signal can be derived from the test suite outcome (binary: issue resolved / not resolved) or from a denser signal based on intermediate test pass rates.</p><p>Future work will explore: (1) using CCA trajectories to fine-tune backbone models for software engineering tasks; (2) designing reward shaping functions that penalize excessive file modifications while rewarding minimal-intervention fixes; and (3) training specialized planning models that generate higher-quality initial plans given retrieved context.</p><h3 id="_6-3-limitations" tabindex="-1">6.3 Limitations <a class="header-anchor" href="#_6-3-limitations" aria-label="Permalink to &quot;6.3 Limitations&quot;">​</a></h3><p>The current system has several limitations:</p><ul><li><strong>Repository size</strong>: CCA&#39;s retrieval phase is optimized for repositories up to ~500k lines. Larger repositories may require additional indexing infrastructure.</li><li><strong>Test dependency</strong>: The verification loop relies on the presence of a runnable test suite. Issues in repositories with complex test setup or slow test execution incur higher latency and cost.</li><li><strong>Note quality degradation</strong>: As note databases grow across many sessions, retrieval precision can degrade. Periodic note consolidation and pruning strategies are left for future work.</li></ul><hr><h2 id="_7-conclusion" tabindex="-1">7. Conclusion <a class="header-anchor" href="#_7-conclusion" aria-label="Permalink to &quot;7. Conclusion&quot;">​</a></h2><p>We presented the Confucius Code Agent (CCA) and the Confucius SDK, an open-source framework for building scalable software engineering agents. CCA achieves 54.3% Resolve@1 on SWE-Bench-Pro using Claude 4.5 Opus, establishing a new state-of-the-art. Our ablation studies demonstrate that scaffold components—particularly context management (F1) and persistent note-taking (F2)—provide significant, measurable performance improvements beyond what backbone model selection alone can deliver.</p><p>The Confucius SDK is designed as a research platform: its modular architecture and standardized interfaces enable controlled experimentation on long-context reasoning, continual memory, and reinforcement learning integration. We believe that open, extensible infrastructure of this kind is essential for the research community to make systematic progress on the challenge of deploying AI agents in production software engineering workflows.</p><p>Code and benchmarks are publicly available under CC BY 4.0.</p><hr><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Wang, X. et al. (2023). SWE-bench: Can Language Models Resolve Real-World GitHub Issues? <em>arXiv:2310.06770</em>.</li><li>Yang, J. et al. (2024). SWE-agent: Agent-Computer Interfaces Enable Automated Software Engineering. <em>arXiv:2405.15793</em>.</li><li>Yao, S. et al. (2023). ReAct: Synergizing Reasoning and Acting in Language Models. <em>ICLR 2023</em>.</li><li>Wang, L. et al. (2024). OpenHands: An Open Platform for AI Software Developers as Generalist Agents. <em>arXiv:2407.16741</em>.</li><li>Patel, A. et al. (2024). Agentless: Demystifying LLM-based Software Engineering Agents. <em>arXiv:2407.01489</em>.</li><li>Packer, C. et al. (2024). MemGPT: Towards LLMs as Operating Systems. <em>arXiv:2310.08560</em>.</li><li>Fernando, C. et al. (2024). Automated Design of Agentic Systems. <em>arXiv:2408.08435</em>.</li><li>Zhao, A. et al. (2024). AFlow: Automating Agentic Workflow Generation. <em>arXiv:2410.10762</em>.</li><li>Chen, M. et al. (2021). Evaluating Large Language Models Trained on Code. <em>arXiv:2107.03374</em>.</li><li>Anthropic (2025). Claude 4.5 Technical Report.</li><li>Li, Y. et al. (2024). SWE-Bench-Pro: A Professional-Grade Benchmark for Software Engineering Agents. <em>Internal technical report</em>.</li><li>Schick, T. et al. (2023). Toolformer: Language Models Can Teach Themselves to Use Tools. <em>NeurIPS 2023</em>.</li><li>Park, J.S. et al. (2023). Generative Agents: Interactive Simulacra of Human Behavior. <em>UIST 2023</em>.</li><li>Hong, S. et al. (2024). MetaGPT: Meta Programming for a Multi-Agent Collaborative Framework. <em>ICLR 2024</em>.</li><li>Xu, C. et al. (2024). CogAgent: A Visual Language Model for GUI Agents. <em>CVPR 2024</em>.</li></ol>',105)])])}const m=t(i,[["render",s]]);export{g as __pageData,m as default};
